void solve(int CASE)
{
	ll n; cin >> n;
	var p = vector<pll>(n + 1);
	fa(i, 1, n) {
		ll a, b; cin >> a >> b;
		p[i] = { a,b };
	}
	sort(all1(p)); // 保证 a = 0 时拿到最大的 b，a = 1 时把能拿的 b 都拿了
	ll ans = 0;
	bool ok = 0;
	fa(i, 1, n) {
		const var& [a, b] = p[i];
		if (a >= 2 and !ok) {
			// a = 0,1 处理完再按公式排序
			ok = 1;
			sort(p.begin() + i, p.end(), [](const var& a, const var& b)->bool {
				const var& [ai, bi] = a;
				const var& [aj, bj] = b;
				// 先 i 后 j  vs  先 j 后 i
				return aj * bi + bj > ai * bj + bi;
				});
		}
		ans = (ans * p[i].px % mod + p[i].py) % mod;
	}
	cout << ans << endl;
	return;
}
